import { GoogleGenAI, Type } from "@google/genai";
import { Stock, AISentiment } from '../types';

const getAiClient = () => {
    // Robust check for API key
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
        console.warn("Gemini API Key is missing. Mocking response.");
        return null;
    }
    return new GoogleGenAI({ apiKey });
};

export const analyzeStock = async (stock: Stock): Promise<AISentiment> => {
    const ai = getAiClient();

    // Mock response if no key available to prevent app crash in demo without env
    if (!ai) {
        return new Promise((resolve) => {
            setTimeout(() => {
                resolve({
                    sentiment: stock.change >= 0 ? 'BULLISH' : 'BEARISH',
                    score: Math.floor(Math.random() * 40) + 60,
                    summary: `AI analysis suggests ${stock.change >= 0 ? 'positive' : 'negative'} momentum for ${stock.name}. Recent volume of ${stock.volume.toLocaleString()} indicates strong institutional interest.`,
                    keyLevels: {
                        support: parseFloat((stock.price * 0.95).toFixed(2)),
                        resistance: parseFloat((stock.price * 1.05).toFixed(2))
                    }
                });
            }, 1500);
        });
    }

    try {
        const prompt = `
            Analyze the following Indian stock data for a day trader:
            Symbol: ${stock.symbol}
            Price: ₹${stock.price}
            Change: ${stock.changePercent}%
            Volume: ${stock.volume}
            Sector: ${stock.sector}

            Provide a JSON response with sentiment (BULLISH, BEARISH, NEUTRAL), a confidence score (0-100), a short 2-sentence summary, and key support/resistance levels.
        `;

        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash-latest",
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        sentiment: { type: Type.STRING, enum: ['BULLISH', 'BEARISH', 'NEUTRAL'] },
                        score: { type: Type.INTEGER },
                        summary: { type: Type.STRING },
                        keyLevels: {
                            type: Type.OBJECT,
                            properties: {
                                support: { type: Type.NUMBER },
                                resistance: { type: Type.NUMBER }
                            }
                        }
                    }
                }
            }
        });

        const text = response.text;
        if (!text) throw new Error("No response text");

        return JSON.parse(text) as AISentiment;

    } catch (error) {
        console.error("Gemini API Error:", error);
        // Fallback
        return {
            sentiment: 'NEUTRAL',
            score: 50,
            summary: "AI services are temporarily unavailable. Please rely on technical indicators.",
            keyLevels: { support: 0, resistance: 0 }
        };
    }
};

import { Candle, Stock } from '../types';

// Helper to generate a random walk candle
export const generateNextCandle = (prevCandle: Candle): Candle => {
  const volatility = 2.0; // Simulated volatility
  const change = (Math.random() - 0.5) * volatility;
  const close = prevCandle.close + change;
  const high = Math.max(prevCandle.close, close) + Math.random() * 1;
  const low = Math.min(prevCandle.close, close) - Math.random() * 1;
  const open = prevCandle.close;

  const now = new Date();
  const time = `${now.getHours().toString().padStart(2, '0')}:${now.getMinutes().toString().padStart(2, '0')}:${now.getSeconds().toString().padStart(2, '0')}`;

  return {
    time,
    open: parseFloat(open.toFixed(2)),
    high: parseFloat(high.toFixed(2)),
    low: parseFloat(low.toFixed(2)),
    close: parseFloat(close.toFixed(2)),
    volume: Math.floor(Math.random() * 10000)
  };
};

export const generateHistoricalCandles = (count: number, startPrice: number): Candle[] => {
  const candles: Candle[] = [];
  let currentPrice = startPrice;
  const now = new Date();

  for (let i = count; i > 0; i--) {
    const timeDate = new Date(now.getTime() - i * 60000); // 1 minute intervals
    const volatility = startPrice * 0.002;
    const change = (Math.random() - 0.5) * volatility * 2;

    const open = currentPrice;
    const close = currentPrice + change;
    const high = Math.max(open, close) + Math.random() * volatility;
    const low = Math.min(open, close) - Math.random() * volatility;

    candles.push({
      time: `${timeDate.getHours().toString().padStart(2, '0')}:${timeDate.getMinutes().toString().padStart(2, '0')}`,
      open: parseFloat(open.toFixed(2)),
      high: parseFloat(high.toFixed(2)),
      low: parseFloat(low.toFixed(2)),
      close: parseFloat(close.toFixed(2)),
      volume: Math.floor(Math.random() * 50000 + 1000)
    });
    currentPrice = close;
  }
  return candles;
};

// Simulate live price updates for the ticker
export const simulateLivePrice = (stock: Stock): Stock => {
    const move = (Math.random() - 0.48) * (stock.price * 0.001); // Slight upward bias
    const newPrice = stock.price + move;
    const newChange = stock.change + move;
    const newPercent = (newChange / stock.prevClose) * 100;

    return {
        ...stock,
        price: parseFloat(newPrice.toFixed(2)),
        change: parseFloat(newChange.toFixed(2)),
        changePercent: parseFloat(newPercent.toFixed(2)),
    };
};

