import { Maximize2, Activity } from 'lucide-react';

interface ChartWidgetProps {
    data: Candle[];
    selectedStock: Stock;
}

const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
        const data = payload[0].payload;
        return (
            <div className="bg-slate-900 border border-slate-700 p-3 rounded shadow-xl font-mono text-xs z-50">
                <p className="text-slate-400 mb-1">{label}</p>
                <div className="grid grid-cols-2 gap-x-4 gap-y-1">
                    <span className="text-slate-400">Open:</span>
                    <span className="text-white text-right">{data.open}</span>
                    <span className="text-slate-400">High:</span>
                    <span className="text-green-400 text-right">{data.high}</span>
                    <span className="text-slate-400">Low:</span>
                    <span className="text-red-400 text-right">{data.low}</span>
                    <span className="text-slate-400">Close:</span>
                    <span className="text-white text-right">{data.close}</span>
                    <span className="text-slate-400">Vol:</span>
                    <span className="text-blue-400 text-right">{data.volume}</span>
                </div>
            </div>
        );
    }
    return null;
};

