                        <span className="text-slate-500 text-xs bg-slate-800 px-1 rounded">NSE</span>
                    </div>
                    <div className="h-4 w-px bg-slate-700 mx-2"></div>
                    <div className="flex gap-1">
                        {TIMEFRAMES.map((tf) => (
                            <button
                                key={tf}
                                onClick={() => setTimeframe(tf)}
