                            dataKey="time" 
                            stroke="#475569" 
                            tick={{fontSize: 10}} 
                            tickMargin={10} 
                            axisLine={false}
                        />
                        <YAxis 
                            domain={['auto', 'auto']} 
                            orientation="right" 
                            stroke="#475569" 
                            tick={{fontSize: 10}} 
