import React, { useState } from 'react';
import { Stock, OrderSide, OrderType } from '../../types';

interface OrderEntryProps {
    stock: Stock;
    onPlaceOrder: (side: OrderSide, quantity: number, price: number) => void;
}

const OrderEntry: React.FC<OrderEntryProps> = ({ stock, onPlaceOrder }) => {
    const [side, setSide] = useState<OrderSide>(OrderSide.BUY);
    const [orderType, setOrderType] = useState<OrderType>(OrderType.MARKET);
    const [quantity, setQuantity] = useState<number>(1);
    const [price, setPrice] = useState<number>(stock.price);

    // Update limit price when switching to limit if empty or old
    React.useEffect(() => {
        if (orderType === OrderType.MARKET) {
            setPrice(stock.price);
        }
    }, [orderType, stock.price]);

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        onPlaceOrder(side, quantity, orderType === OrderType.MARKET ? stock.price : price);
    };

    const totalValue = quantity * (orderType === OrderType.MARKET ? stock.price : price);

    return (
        <div className="bg-slate-900 border border-slate-800 rounded-lg p-4 flex flex-col h-full">
            <div className="flex bg-slate-800 rounded-lg p-1 mb-4">
                <button
                    onClick={() => setSide(OrderSide.BUY)}
                    className={`flex-1 py-2 text-sm font-semibold rounded-md transition-all ${
                        side === OrderSide.BUY 
                        ? 'bg-green-600 text-white shadow-lg' 
                        : 'text-slate-400 hover:text-white'
                    }`}
                >
                    Buy
                </button>
                <button
                    onClick={() => setSide(OrderSide.SELL)}
                    className={`flex-1 py-2 text-sm font-semibold rounded-md transition-all ${
                        side === OrderSide.SELL 
                        ? 'bg-red-600 text-white shadow-lg' 
                        : 'text-slate-400 hover:text-white'
                    }`}
                >
                    Sell
                </button>
            </div>

            <div className="flex gap-2 mb-4">
                 <button
                    onClick={() => setOrderType(OrderType.MARKET)}
                    className={`flex-1 py-1 text-xs border rounded transition-colors ${
                        orderType === OrderType.MARKET 
                        ? 'border-blue-500 text-blue-400 bg-blue-500/10' 
                        : 'border-slate-700 text-slate-500'
                    }`}
                >
                    Market
                </button>
                <button
                    onClick={() => setOrderType(OrderType.LIMIT)}
                    className={`flex-1 py-1 text-xs border rounded transition-colors ${
                        orderType === OrderType.LIMIT 
                        ? 'border-blue-500 text-blue-400 bg-blue-500/10' 
                        : 'border-slate-700 text-slate-500'
                    }`}
                >
                    Limit
                </button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-4 flex-1">
                <div>
                    <label className="text-xs text-slate-500 font-medium mb-1 block">Quantity (Qty)</label>
                    <input 
                        type="number" 
                        min="1"
                        value={quantity}
                        onChange={(e) => setQuantity(parseInt(e.target.value) || 0)}
                        className="w-full bg-slate-950 border border-slate-700 rounded p-2 text-white text-right font-mono focus:border-blue-500 focus:outline-none transition-colors"
                    />
                </div>

                <div>
                    <label className="text-xs text-slate-500 font-medium mb-1 block">Price (₹)</label>
                    <input 
                        type="number" 
                        step="0.05"
                        disabled={orderType === OrderType.MARKET}
                        value={orderType === OrderType.MARKET ? stock.price.toFixed(2) : price}
                        onChange={(e) => setPrice(parseFloat(e.target.value) || 0)}
                        className={`w-full bg-slate-950 border border-slate-700 rounded p-2 text-white text-right font-mono focus:border-blue-500 focus:outline-none transition-colors ${orderType === OrderType.MARKET ? 'opacity-50 cursor-not-allowed' : ''}`}
                    />
                </div>

                <div className="pt-4 border-t border-slate-800">
                    <div className="flex justify-between items-center mb-1">
                        <span className="text-xs text-slate-500">Margin Required</span>
                        <span className="text-sm font-mono text-white">₹{totalValue.toLocaleString('en-IN', { maximumFractionDigits: 2 })}</span>
                    </div>
                    <div className="flex justify-between items-center">
                        <span className="text-xs text-slate-500">Available</span>
                        <span className="text-xs font-mono text-green-400">₹1,50,000.00</span>
                    </div>
                </div>

                <button 
                    type="submit"
