import { GoogleGenAI, Type, Chat } from "@google/genai";
import { Stock, AISentiment } from '../types';

const getAiClient = () => {
    // Robust check for API key
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
        console.warn("Gemini API Key is missing. Mocking response.");
        return null;
    }
    return new GoogleGenAI({ apiKey });
};

export const analyzeStock = async (stock: Stock): Promise<AISentiment> => {
    const ai = getAiClient();

    // Mock response if no key available to prevent app crash in demo without env
    if (!ai) {
        return new Promise((resolve) => {
            setTimeout(() => {
                resolve({
                    sentiment: stock.change >= 0 ? 'BULLISH' : 'BEARISH',
                    score: Math.floor(Math.random() * 40) + 60,
                    summary: `AI analysis suggests ${stock.change >= 0 ? 'positive' : 'negative'} momentum for ${stock.name}. Recent volume of ${stock.volume.toLocaleString()} indicates strong institutional interest.`,
                    keyLevels: {
                        support: parseFloat((stock.price * 0.95).toFixed(2)),
                        resistance: parseFloat((stock.price * 1.05).toFixed(2))
                    }
                });
            }, 1500);
        });
    }

    try {
        const prompt = `
            Analyze the following Indian stock data for a day trader:
            Symbol: ${stock.symbol}
            Price: ₹${stock.price}
            Change: ${stock.changePercent}%
            Volume: ${stock.volume}
            Sector: ${stock.sector}

            Provide a JSON response with sentiment (BULLISH, BEARISH, NEUTRAL), a confidence score (0-100), a short 2-sentence summary, and key support/resistance levels.
        `;

        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        sentiment: { type: Type.STRING, enum: ['BULLISH', 'BEARISH', 'NEUTRAL'] },
                        score: { type: Type.INTEGER },
                        summary: { type: Type.STRING },
                        keyLevels: {
                            type: Type.OBJECT,
                            properties: {
                                support: { type: Type.NUMBER },
                                resistance: { type: Type.NUMBER }
                            }
                        }
                    }
                }
            }
        });

        const text = response.text;
        if (!text) throw new Error("No response text");

        return JSON.parse(text) as AISentiment;

    } catch (error) {
        console.error("Gemini API Error:", error);
        // Fallback
        return {
            sentiment: 'NEUTRAL',
            score: 50,
            summary: "AI services are temporarily unavailable. Please rely on technical indicators.",
            keyLevels: { support: 0, resistance: 0 }
        };
    }
};

export const createChatSession = (): Chat | null => {
    const ai = getAiClient();
    if (!ai) return null;

    return ai.chats.create({
        model: "gemini-3-pro-preview",
        config: {
            systemInstruction: "You are an expert trading assistant for IndiTrade Pro. Help users with stock market terminology, trading strategies, technical analysis, and understanding market trends. Keep responses concise, professional, and helpful for day traders.",
        }
    });
};

import React, { useState, useRef, useEffect } from 'react';
import { MessageSquare, Send, Loader2, Minimize2, X } from 'lucide-react';
import { createChatSession } from '../../services/geminiService';
import { ChatMessage } from '../../types';
import { Chat, GenerateContentResponse } from "@google/genai";

const ChatBot: React.FC = () => {
    const [isOpen, setIsOpen] = useState(false);
    const [messages, setMessages] = useState<ChatMessage[]>([
        { role: 'model', text: 'Hello! I am your IndiTrade AI assistant. How can I help you with your trading today?', timestamp: new Date() }
    ]);
    const [input, setInput] = useState('');
    const [isTyping, setIsTyping] = useState(false);
    const chatSessionRef = useRef<Chat | null>(null);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    // Initialize chat session
    useEffect(() => {
        if (isOpen && !chatSessionRef.current) {
            chatSessionRef.current = createChatSession();
        }
    }, [isOpen]);

    // Auto-scroll
    useEffect(() => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, [messages]);

    const handleSend = async () => {
        if (!input.trim()) return;

        const userMsg: ChatMessage = { role: 'user', text: input, timestamp: new Date() };
        setMessages(prev => [...prev, userMsg]);
        setInput('');
        setIsTyping(true);

        try {
            if (!chatSessionRef.current) {
                // Fallback mock if no API key/client
                setTimeout(() => {
                    setMessages(prev => [...prev, { 
                        role: 'model', 
                        text: "I'm currently running in demo mode (no API key). In production, I would answer: " + input, 
                        timestamp: new Date() 
                    }]);
                    setIsTyping(false);
                }, 1000);
                return;
            }

            const result = await chatSessionRef.current.sendMessageStream({ message: input });

            // Add placeholder for bot message
            setMessages(prev => [...prev, { role: 'model', text: '', timestamp: new Date() }]);

            let fullText = '';
            for await (const chunk of result) {
                const c = chunk as GenerateContentResponse;
                const text = c.text || '';
                fullText += text;

                setMessages(prev => {
                    const newArr = [...prev];
                    const lastMsg = newArr[newArr.length - 1];
                    if (lastMsg.role === 'model') {
                        lastMsg.text = fullText;
                    }
                    return newArr;
                });
            }
        } catch (error) {
            console.error("Chat Error", error);
            setMessages(prev => [...prev, { role: 'model', text: "Sorry, I encountered an error connecting to the AI service.", timestamp: new Date() }]);
        } finally {
            setIsTyping(false);
        }
    };

    return (
        <>
            {/* Toggle Button */}
            {!isOpen && (
                <button 
                    onClick={() => setIsOpen(true)}
                    className="fixed bottom-6 right-6 w-14 h-14 bg-blue-600 hover:bg-blue-500 rounded-full flex items-center justify-center shadow-lg shadow-blue-900/40 transition-all hover:scale-105 z-50 text-white"
                >
                    <MessageSquare size={24} />
                </button>
            )}

            {/* Chat Window */}
            {isOpen && (
                <div className="fixed bottom-6 right-6 w-80 md:w-96 h-[500px] bg-slate-900 border border-slate-700 rounded-xl shadow-2xl flex flex-col z-50 overflow-hidden animate-in fade-in slide-in-from-bottom-10 duration-200">
                    {/* Header */}
                    <div className="bg-slate-800 p-4 flex justify-between items-center border-b border-slate-700">
                        <div className="flex items-center gap-2">
                            <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></div>
                            <h3 className="font-bold text-white text-sm">IndiTrade AI</h3>
                        </div>
                        <button onClick={() => setIsOpen(false)} className="text-slate-400 hover:text-white transition-colors">
                            <X size={18} />
                        </button>
                    </div>

                    {/* Messages */}
                    <div className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar bg-slate-900/50">
                        {messages.map((msg, idx) => (
                            <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                                <div className={`max-w-[85%] p-3 rounded-lg text-sm leading-relaxed ${
                                    msg.role === 'user' 
                                    ? 'bg-blue-600 text-white rounded-tr-none' 
                                    : 'bg-slate-800 text-slate-200 rounded-tl-none border border-slate-700'
                                }`}>
                                    {msg.text}
                                    <div className={`text-[10px] mt-1 opacity-50 ${msg.role === 'user' ? 'text-blue-200' : 'text-slate-500'}`}>
                                        {msg.timestamp.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                                    </div>
                                </div>
                            </div>
                        ))}
                        {isTyping && (
                            <div className="flex justify-start">
                                <div className="bg-slate-800 border border-slate-700 p-3 rounded-lg rounded-tl-none flex gap-1">
                                    <div className="w-1.5 h-1.5 bg-slate-500 rounded-full animate-bounce"></div>
                                    <div className="w-1.5 h-1.5 bg-slate-500 rounded-full animate-bounce delay-100"></div>
                                    <div className="w-1.5 h-1.5 bg-slate-500 rounded-full animate-bounce delay-200"></div>
                                </div>
                            </div>
                        )}
                        <div ref={messagesEndRef} />
                    </div>

                    {/* Input */}
                    <div className="p-3 bg-slate-800 border-t border-slate-700">
                        <div className="flex gap-2">
                            <input 
                                type="text"
                                value={input}
                                onChange={(e) => setInput(e.target.value)}
                                onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                                placeholder="Ask about markets..."
                                className="flex-1 bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:border-blue-500"
                            />
                            <button 
                                onClick={handleSend}
                                disabled={isTyping || !input.trim()}
                                className="p-2 bg-blue-600 hover:bg-blue-500 text-white rounded-lg disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                            >
                                {isTyping ? <Loader2 size={18} className="animate-spin" /> : <Send size={18} />}
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </>
    );
};

