import React, { useState, useEffect } from 'react';
import { Stock, OrderSide, OrderType, ProductType, OrderVariety } from '../../types';
import { Info, AlertCircle } from 'lucide-react';

interface OrderEntryProps {
    stock: Stock;
    onPlaceOrder: (order: any) => void;
}

const OrderEntry: React.FC<OrderEntryProps> = ({ stock, onPlaceOrder }) => {
    const [side, setSide] = useState<OrderSide>(OrderSide.BUY);
    const [product, setProduct] = useState<ProductType>(ProductType.MIS);
    const [variety, setVariety] = useState<OrderVariety>(OrderVariety.REGULAR);
    const [orderType, setOrderType] = useState<OrderType>(OrderType.MARKET);

    const [quantity, setQuantity] = useState<number>(1);
    const [price, setPrice] = useState<number>(stock.price);
    const [triggerPrice, setTriggerPrice] = useState<number>(0);
    const [targetPrice, setTargetPrice] = useState<number>(0); // For BO
    const [stopLossPrice, setStopLossPrice] = useState<number>(0); // For BO

    // Reset/Sync prices when stock changes
    useEffect(() => {
        if (orderType === OrderType.MARKET) {
            setPrice(stock.price);
        }
        // Set reasonable defaults for BO/CO
        if (stock.price > 0) {
            setTargetPrice(parseFloat((stock.price * 1.02).toFixed(2)));
            setStopLossPrice(parseFloat((stock.price * 0.98).toFixed(2)));
            setTriggerPrice(parseFloat((stock.price * 0.99).toFixed(2)));
        }
    }, [stock.symbol, stock.price, orderType]);

    // Handle variety changes
    useEffect(() => {
        if (variety === OrderVariety.BO || variety === OrderVariety.CO) {
            setProduct(ProductType.MIS); // BO/CO are usually Intraday
        }
    }, [variety]);

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        onPlaceOrder({
            side,
            product,
            variety,
            type: orderType,
            quantity,
            // For Market and SL-M (Stop Loss Market), execution is at market price, so we send 0 or stock price for simulation
            price: (orderType === OrderType.MARKET || orderType === OrderType.SL_M) ? 0 : price,
            triggerPrice: (orderType === OrderType.SL || orderType === OrderType.SL_M || variety === OrderVariety.CO) ? triggerPrice : undefined,
            targetPrice: variety === OrderVariety.BO ? targetPrice : undefined,
            stopLossPrice: variety === OrderVariety.BO ? stopLossPrice : undefined
        });
    };

    // Margin Calculation Logic
    const calculateMargin = () => {
        let leverage = 1;
        if (product === ProductType.MIS) leverage = 5;
        if (variety === OrderVariety.CO) leverage = 10; // Higher leverage for CO
        if (variety === OrderVariety.BO) leverage = 10; // Higher leverage for BO

        let execPrice = price;
        if (orderType === OrderType.MARKET) {
            execPrice = stock.price;
        } else if (orderType === OrderType.SL_M) {
            // For SL-M, we use trigger price as estimation, or stock price if not set
            execPrice = triggerPrice > 0 ? triggerPrice : stock.price;
        }

        return (execPrice * quantity) / leverage;
    };

    const marginRequired = calculateMargin();
    const availableMargin = 150000; // Mocked

    return (
        <div className="bg-slate-900 border border-slate-800 rounded-lg flex flex-col h-full overflow-hidden">
            {/* Header / Tabs */}
            <div className="flex bg-slate-800">
                <button
                    onClick={() => setSide(OrderSide.BUY)}
                    className={`flex-1 py-3 text-sm font-bold transition-all ${
                        side === OrderSide.BUY 
                        ? 'bg-blue-600 text-white' 
                        : 'text-slate-400 hover:text-white hover:bg-slate-700'
                    }`}
                >
                    BUY
                </button>
                <button
                    onClick={() => setSide(OrderSide.SELL)}
                    className={`flex-1 py-3 text-sm font-bold transition-all ${
                        side === OrderSide.SELL 
                        ? 'bg-red-600 text-white' 
                        : 'text-slate-400 hover:text-white hover:bg-slate-700'
                    }`}
                >
                    SELL
                </button>
            </div>

            <div className="p-4 flex-1 flex flex-col overflow-y-auto custom-scrollbar">

                {/* Product & Variety Selectors */}
                <div className="grid grid-cols-2 gap-3 mb-4">
                    <div>
                        <label className="text-[10px] text-slate-500 font-bold uppercase mb-1 block">Product</label>
                        <div className="flex bg-slate-950 rounded p-1 border border-slate-700">
                            <button 
                                onClick={() => setProduct(ProductType.MIS)}
                                className={`flex-1 text-xs py-1 rounded transition-colors ${product === ProductType.MIS ? 'bg-slate-700 text-white' : 'text-slate-500'}`}
                            >
                                Intraday
                            </button>
                            <button 
                                onClick={() => setProduct(ProductType.CNC)}
                                disabled={variety !== OrderVariety.REGULAR}
                                className={`flex-1 text-xs py-1 rounded transition-colors ${product === ProductType.CNC ? 'bg-slate-700 text-white' : 'text-slate-500'} ${variety !== OrderVariety.REGULAR ? 'opacity-50' : ''}`}
                            >
                                Longterm
                            </button>
                        </div>
                    </div>
                    <div>
                        <label className="text-[10px] text-slate-500 font-bold uppercase mb-1 block">Variety</label>
                        <select 
                            value={variety}
                            onChange={(e) => setVariety(e.target.value as OrderVariety)}
                            className="w-full bg-slate-950 border border-slate-700 rounded py-1.5 px-2 text-xs text-white focus:outline-none focus:border-blue-500"
                        >
                            <option value={OrderVariety.REGULAR}>Regular</option>
                            <option value={OrderVariety.BO}>Bracket (BO)</option>
                            <option value={OrderVariety.CO}>Cover (CO)</option>
                            <option value={OrderVariety.AMO}>AMO</option>
                        </select>
                    </div>
                </div>

                {/* Order Type Selector */}
                <div className="mb-4">
                     <label className="text-[10px] text-slate-500 font-bold uppercase mb-1 block">Order Type</label>
                     <div className="flex gap-2">
                        {[OrderType.MARKET, OrderType.LIMIT, OrderType.SL, OrderType.SL_M].map(t => (
                            <button
                                key={t}
                                onClick={() => setOrderType(t)}
                                className={`flex-1 py-1.5 text-[10px] font-bold border rounded transition-colors ${
                                    orderType === t 
                                    ? 'border-blue-500 text-blue-400 bg-blue-500/10' 
                                    : 'border-slate-700 text-slate-500 hover:border-slate-600'
                                }`}
                            >
                                {t}
                            </button>
                        ))}
                     </div>
                </div>

                <form onSubmit={handleSubmit} className="space-y-4">
                    {/* Qty & Price Row */}
                    <div className="grid grid-cols-2 gap-3">
                        <div>
                            <label className="text-[10px] text-slate-500 font-bold uppercase mb-1 block">Qty</label>
                            <input 
                                type="number" 
                                min="1"
                                value={quantity}
                                onChange={(e) => setQuantity(parseInt(e.target.value) || 0)}
                                className="w-full bg-slate-950 border border-slate-700 rounded p-2 text-white text-right font-mono text-sm focus:border-blue-500 focus:outline-none"
                            />
                        </div>
                        <div>
                            <label className="text-[10px] text-slate-500 font-bold uppercase mb-1 block">Price</label>
                            <input 
                                type="number" 
                                step="0.05"
                                disabled={orderType === OrderType.MARKET || orderType === OrderType.SL_M}
                                value={orderType === OrderType.MARKET || orderType === OrderType.SL_M ? 0 : price}
                                onChange={(e) => setPrice(parseFloat(e.target.value) || 0)}
                                className={`w-full bg-slate-950 border border-slate-700 rounded p-2 text-white text-right font-mono text-sm focus:border-blue-500 focus:outline-none ${
                                    orderType === OrderType.MARKET || orderType === OrderType.SL_M ? 'opacity-30 cursor-not-allowed' : ''
                                }`}
                            />
                        </div>
                    </div>

                    {/* Trigger Price (SL/SL-M/CO) */}
                    {(orderType === OrderType.SL || orderType === OrderType.SL_M || variety === OrderVariety.CO) && (
                        <div>
                            <label className="text-[10px] text-slate-500 font-bold uppercase mb-1 block flex justify-between">
                                Trigger Price
                                {variety === OrderVariety.CO && <span className="text-blue-400 text-[9px] lowercase">stop loss trigger</span>}
                            </label>
                            <input 
                                type="number" 
                                step="0.05"
                                value={triggerPrice}
                                onChange={(e) => setTriggerPrice(parseFloat(e.target.value) || 0)}
                                className="w-full bg-slate-950 border border-slate-700 rounded p-2 text-white text-right font-mono text-sm focus:border-blue-500 focus:outline-none border-l-4 border-l-yellow-500"
                            />
                        </div>
                    )}

                    {/* Bracket Order Fields */}
                    {variety === OrderVariety.BO && (
                        <div className="grid grid-cols-2 gap-3 p-3 bg-slate-950 rounded border border-slate-800">
                             <div>
                                <label className="text-[10px] text-green-500 font-bold uppercase mb-1 block">Target</label>
                                <input 
                                    type="number" 
                                    step="0.05"
                                    value={targetPrice}
                                    onChange={(e) => setTargetPrice(parseFloat(e.target.value) || 0)}
                                    className="w-full bg-slate-900 border border-slate-700 rounded p-1.5 text-white text-right font-mono text-xs focus:border-green-500 focus:outline-none"
                                />
                                <div className="text-[9px] text-right text-green-500 mt-1">
                                    +{(targetPrice - (orderType === OrderType.MARKET ? stock.price : price)).toFixed(2)}
                                </div>
                            </div>
                            <div>
                                <label className="text-[10px] text-red-500 font-bold uppercase mb-1 block">Stop Loss</label>
                                <input 
                                    type="number" 
                                    step="0.05"
                                    value={stopLossPrice}
                                    onChange={(e) => setStopLossPrice(parseFloat(e.target.value) || 0)}
                                    className="w-full bg-slate-900 border border-slate-700 rounded p-1.5 text-white text-right font-mono text-xs focus:border-red-500 focus:outline-none"
                                />
                                <div className="text-[9px] text-right text-red-500 mt-1">
                                    {(stopLossPrice - (orderType === OrderType.MARKET ? stock.price : price)).toFixed(2)}
                                </div>
                            </div>
                        </div>
                    )}

                    {/* Margin Info */}
                    <div className="bg-slate-800/50 rounded p-3 space-y-2">
                        <div className="flex justify-between items-center">
                            <span className="text-xs text-slate-400">Required Margin</span>
                            <span className={`text-sm font-mono font-bold ${marginRequired > availableMargin ? 'text-red-500' : 'text-white'}`}>
                                ₹{marginRequired.toLocaleString('en-IN', { maximumFractionDigits: 2 })}
                            </span>
                        </div>
                        <div className="flex justify-between items-center">
                            <span className="text-xs text-slate-400">Available</span>
                            <span className="text-xs font-mono text-slate-300">₹{availableMargin.toLocaleString('en-IN')}</span>
                        </div>
                        {marginRequired > availableMargin && (
                             <div className="flex items-center gap-1 text-[10px] text-red-400">
                                <AlertCircle size={10} /> Insufficient funds
                             </div>
                        )}
                    </div>
                </form>
            </div>

            {/* Submit Button */}
            <div className="p-4 bg-slate-900 border-t border-slate-800">
                <button 
                    onClick={handleSubmit}
                    className={`w-full py-3.5 rounded-lg font-bold text-white transition-all transform active:scale-[0.98] shadow-lg flex items-center justify-center gap-2 ${
                        side === OrderSide.BUY 
                        ? 'bg-blue-600 hover:bg-blue-500 shadow-blue-900/20' 
                        : 'bg-red-600 hover:bg-red-500 shadow-red-900/20'
                    }`}
                >
                    {side} {stock.symbol}
                </button>
            </div>
        </div>
    );
};

