const DashboardPage: React.FC = () => {
    const [collapsed, setCollapsed] = useState(false);
    const [activeTab, setActiveTab] = useState('dashboard');
    const [selectedStock, setSelectedStock] = useState<Stock>(MOCK_STOCKS[0]);
    const [candles, setCandles] = useState<Candle[]>([]);
    const [aiAnalysis, setAiAnalysis] = useState<AISentiment | null>(null);
    const [isAnalyzing, setIsAnalyzing] = useState(false);
    const [stocks, setStocks] = useState<Stock[]>(MOCK_STOCKS);
    const [searchQuery, setSearchQuery] = useState('');
    const [isSearching, setIsSearching] = useState(false);

    // Initial Data Load
    useEffect(() => {
        setCandles(generateHistoricalCandles(100, selectedStock.price));
        handleAiAnalysis(selectedStock);
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [selectedStock.symbol]);

    // Live Data Simulation
    useEffect(() => {
        const interval = setInterval(() => {
            // Update all stocks slightly
            setStocks(prev => prev.map(s => simulateLivePrice(s)));

            // Update chart for selected stock
            setCandles(prev => {
                const last = prev[prev.length - 1];
                const newCandle = generateNextCandle(last);
                return [...prev.slice(1), newCandle];
            });

            // Update selected stock price locally to match chart
            setSelectedStock(prev => {
               const live = stocks.find(s => s.symbol === prev.symbol);
               return live ? live : prev;
            });

        }, 2000); // 2 second Tick

        return () => clearInterval(interval);
    }, [stocks]); // Dependency on stocks to keep sync

    const handleAiAnalysis = async (stock: Stock) => {
        setIsAnalyzing(true);
        setAiAnalysis(null);
        const result = await analyzeStock(stock);
        setAiAnalysis(result);
        setIsAnalyzing(false);
    };

    const handleOrder = (order: any) => {
        // Construct the full description based on order variety
        let priceText = '';
        if (order.type === 'MARKET') priceText = 'MKT';
        else if (order.type === 'SL-M') priceText = 'MKT (SL)';
        else priceText = '₹' + order.price;

        let desc = `${order.side} ${order.quantity} ${selectedStock.symbol} @ ${priceText}`;

        if (order.variety === 'BO') {
            desc += ` [BO] Tgt: ${order.targetPrice} SL: ${order.stopLossPrice}`;
        } else if (order.variety === 'CO') {
            desc += ` [CO] Trig: ${order.triggerPrice}`;
        } else if (order.type === 'SL' || order.type === 'SL-M') {
            desc += ` Trig: ${order.triggerPrice}`;
        }

        alert(`Order Placed Successfully!\n\n${desc}\nProduct: ${order.product}`);
    };

    const handleSearch = async (e: React.KeyboardEvent<HTMLInputElement>) => {
        if (e.key === 'Enter' && searchQuery.trim()) {
            setIsSearching(true);
            try {
                // If the stock is already in our list, just select it
                const existing = stocks.find(s => s.symbol === searchQuery.toUpperCase());
                if (existing) {
                    setSelectedStock(existing);
                    handleAiAnalysis(existing);
                    if (activeTab !== 'dashboard') setActiveTab('dashboard'); // Switch to main view
                    setSearchQuery('');
                    setIsSearching(false);
                    return;
                }

                // If not, fetch it (simulated)
                const stock = await searchStock(searchQuery);
                if (stock) {
                    // Add to stocks list (Watchlist)
                    setStocks(prev => [stock, ...prev]);
                    // Select it
                    setSelectedStock(stock);
                    // Generate new chart data for this stock
                    setCandles(generateHistoricalCandles(100, stock.price));
                    // Analyze
                    handleAiAnalysis(stock);

                    if (activeTab !== 'dashboard') setActiveTab('dashboard'); // Switch to main view
                    setSearchQuery('');
                }
            } catch (error) {
                console.error("Search failed", error);
            } finally {
                setIsSearching(false);
            }
        }
    };

    const renderContent = () => {
        switch(activeTab) {
            case 'dashboard':
                return <DashboardHome 
                    stocks={stocks} 
                    selectedStock={selectedStock} 
                    setSelectedStock={setSelectedStock}
                    candles={candles}
                    handleOrder={handleOrder}
                    aiAnalysis={aiAnalysis}
                    isAnalyzing={isAnalyzing}
                    handleAiAnalysis={handleAiAnalysis}
                />;
            case 'markets': return <MarketsView />;
            case 'portfolio': return <PortfolioView />;
            case 'orders': return <OrdersView />;
            case 'watchlist': return <DashboardHome 
                stocks={stocks} 
                selectedStock={selectedStock} 
                setSelectedStock={setSelectedStock}
                candles={candles}
                handleOrder={handleOrder}
                aiAnalysis={aiAnalysis}
                isAnalyzing={isAnalyzing}
                handleAiAnalysis={handleAiAnalysis}
            />; // Reusing dashboard for watchlist focus for now
            case 'analytics': return <AnalyticsView />;
            case 'news': return <NewsView />;
            case 'alerts': return <AlertsView />;
            case 'settings': return <SettingsView />;
            default: return <div className="text-white">Page not found</div>;
        }
    };

    return (
        <div className="flex h-screen bg-slate-950 text-slate-100 overflow-hidden font-sans">
            <Sidebar 
                collapsed={collapsed} 
                setCollapsed={setCollapsed} 
                activeTab={activeTab} 
                setActiveTab={setActiveTab}
                onLogout={() => window.location.hash = ''} 
            />

            <main className="flex-1 flex flex-col min-w-0">
                <MarketTicker />

                {/* Header */}
                <header className="h-16 border-b border-slate-800 bg-slate-900/50 backdrop-blur flex items-center justify-between px-6 z-10">
                    <div className="flex items-center bg-slate-800 rounded-lg px-3 py-2 w-96 border border-slate-700 focus-within:border-blue-500 transition-colors">
                        {isSearching ? <Loader2 size={18} className="text-blue-500 animate-spin mr-2" /> : <Search size={18} className="text-slate-400 mr-2" />}
                        <input 
                            type="text" 
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            onKeyDown={handleSearch}
                            disabled={isSearching}
                            placeholder="Search NSE/BSE (e.g., ZOMATO, PAYTM)" 
                            className="bg-transparent border-none focus:outline-none text-sm text-white w-full placeholder-slate-500"
                        />
                        <span className="text-xs text-slate-500 border border-slate-600 px-1.5 rounded">Enter</span>
                    </div>

                    <div className="flex items-center gap-4">
                        <button className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded-full transition-colors relative">
                            <Bell size={20} />
                            <span className="absolute top-2 right-2 w-2 h-2 bg-red-500 rounded-full border border-slate-900"></span>
                        </button>
                        <div className="flex items-center gap-3 pl-4 border-l border-slate-700">
                            <div className="text-right hidden md:block">
                                <p className="text-sm font-medium text-white">Aditya Kumar</p>
                                <p className="text-xs text-slate-400">Pro Trader</p>
                            </div>
                            <div className="w-9 h-9 bg-gradient-to-br from-blue-500 to-purple-600 rounded-full flex items-center justify-center text-sm font-bold shadow-lg">AK</div>
                        </div>
                    </div>
                </header>

                {/* Main Content Area */}
                <div className="flex-1 overflow-y-auto p-4 md:p-6 relative">
                    {renderContent()}
                </div>
            </main>
            {/* ChatBot Overlay */}
            <ChatBot />
        </div>
    );
};

