import { GoogleGenAI, Type, Chat } from "@google/genai";
import { Stock, AISentiment } from '../types';

const getAiClient = () => {
    // Robust check for API key
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
        console.warn("Gemini API Key is missing. Mocking response.");
        return null;
    }
    return new GoogleGenAI({ apiKey });
};

export const analyzeStock = async (stock: Stock): Promise<AISentiment> => {
    const ai = getAiClient();

    // Mock response if no key available to prevent app crash in demo without env
    if (!ai) {
        return new Promise((resolve) => {
            setTimeout(() => {
                resolve({
                    sentiment: stock.change >= 0 ? 'BULLISH' : 'BEARISH',
                    score: Math.floor(Math.random() * 40) + 60,
                    summary: `AI analysis suggests ${stock.change >= 0 ? 'positive' : 'negative'} momentum for ${stock.name}. Recent volume of ${stock.volume.toLocaleString()} indicates strong institutional interest.`,
                    keyLevels: {
                        support: parseFloat((stock.price * 0.95).toFixed(2)),
                        resistance: parseFloat((stock.price * 1.05).toFixed(2))
                    }
                });
            }, 1500);
        });
    }

    try {
        const prompt = `
            Analyze the following Indian stock data for a day trader:
            Symbol: ${stock.symbol}
            Price: ₹${stock.price}
            Change: ${stock.changePercent}%
            Volume: ${stock.volume}
            Sector: ${stock.sector}

            Provide a JSON response with sentiment (BULLISH, BEARISH, NEUTRAL), a confidence score (0-100), a short 2-sentence summary, and key support/resistance levels.
        `;

        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        sentiment: { type: Type.STRING, enum: ['BULLISH', 'BEARISH', 'NEUTRAL'] },
                        score: { type: Type.INTEGER },
                        summary: { type: Type.STRING },
                        keyLevels: {
                            type: Type.OBJECT,
                            properties: {
                                support: { type: Type.NUMBER },
                                resistance: { type: Type.NUMBER }
                            }
                        }
                    }
                }
            }
        });

        const text = response.text;
        if (!text) throw new Error("No response text");

        return JSON.parse(text) as AISentiment;

    } catch (error) {
        console.error("Gemini API Error:", error);
        // Fallback
        return {
            sentiment: 'NEUTRAL',
            score: 50,
            summary: "AI services are temporarily unavailable. Please rely on technical indicators.",
            keyLevels: { support: 0, resistance: 0 }
        };
    }
};

export const createChatSession = (): Chat | null => {
    const ai = getAiClient();
    if (!ai) return null;

    return ai.chats.create({
        model: "gemini-3-pro-preview",
        config: {
            systemInstruction: "You are an expert trading assistant for IndiTrade Pro. Help users with stock market terminology, trading strategies, technical analysis, and understanding market trends. Keep responses concise, professional, and helpful for day traders.",
        }
    });
};

export const fetchLiveMarketData = async (symbols: string[]): Promise<Partial<Stock>[]> => {
    const ai = getAiClient();
    if (!ai) return [];

    try {
        // Use Gemini with Google Search to get real-time snapshots
        const prompt = `
            Get the current Live Traded Price (LTP) and today's percentage change for these Indian Stocks: ${symbols.join(', ')}.
            Return a JSON array of objects with keys: "symbol" (uppercase), "price" (number), "changePercent" (number).
            Ensure the prices are for NSE/BSE.
        `;

        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: prompt,
            config: {
                tools: [{ googleSearch: {} }],
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            symbol: { type: Type.STRING },
                            price: { type: Type.NUMBER },
                            changePercent: { type: Type.NUMBER }
                        }
                    }
                }
            }
        });

        const text = response.text;
        // Search grounding logs for debugging/display if needed
        console.log("Grounding Metadata:", response.candidates?.[0]?.groundingMetadata?.groundingChunks);

        if (!text) return [];
        return JSON.parse(text) as Partial<Stock>[];

    } catch (e) {
        console.error("Failed to fetch live data via Gemini", e);
        return [];
    }
};

import { Candle, Stock } from '../types';
import { MOCK_STOCKS } from '../constants';

// --- WebSocket Simulation Service ---

type MarketListener = (stock: Stock) => void;

export class MarketSocket {
    private isConnected: boolean = false;
    private subscribers: Map<string, MarketListener[]> = new Map();
    private intervalId: any = null;
    private stocks: Map<string, Stock> = new Map();

    constructor(initialStocks: Stock[]) {
        initialStocks.forEach(s => this.stocks.set(s.symbol, s));
    }

    // Simulate connection
    connect(): Promise<boolean> {
        return new Promise((resolve) => {
            setTimeout(() => {
                this.isConnected = true;
                this.startFeed();
                resolve(true);
            }, 800);
        });
    }

    disconnect() {
        this.isConnected = false;
        if (this.intervalId) clearInterval(this.intervalId);
    }

    subscribe(symbol: string, callback: MarketListener) {
        if (!this.subscribers.has(symbol)) {
            this.subscribers.set(symbol, []);
        }
        this.subscribers.get(symbol)?.push(callback);
    }

    unsubscribe(symbol: string, callback: MarketListener) {
        const subs = this.subscribers.get(symbol);
        if (subs) {
            this.subscribers.set(symbol, subs.filter(cb => cb !== callback));
        }
    }

    updateStockData(updates: Partial<Stock>[]) {
        updates.forEach(u => {
            if (u.symbol && this.stocks.has(u.symbol)) {
                const current = this.stocks.get(u.symbol)!;
                const updated = { ...current, ...u };
                // Recalculate change value based on percent if needed
                if (u.changePercent !== undefined && u.price !== undefined) {
                    updated.change = parseFloat((u.price - (u.price / (1 + u.changePercent / 100))).toFixed(2));
                }
                this.stocks.set(u.symbol, updated);
            }
        });
    }

    private startFeed() {
        // High frequency tick simulation
        this.intervalId = setInterval(() => {
            if (!this.isConnected) return;

            this.stocks.forEach((stock, symbol) => {
                // Simulate tick
                const volatility = 0.0005; // 0.05% volatility per tick
                const move = (Math.random() - 0.48) * (stock.price * volatility); 
                const newPrice = parseFloat((stock.price + move).toFixed(2));
                const newChange = parseFloat((stock.change + move).toFixed(2));
                const newPercent = parseFloat(((newChange / (stock.price - stock.change)) * 100).toFixed(2));

                const updatedStock = {
                    ...stock,
                    price: newPrice,
                    change: newChange,
                    changePercent: newPercent,
                    volume: stock.volume + Math.floor(Math.random() * 50)
                };

                this.stocks.set(symbol, updatedStock);

                // Notify subscribers
                const subs = this.subscribers.get(symbol);
                if (subs) {
                    subs.forEach(cb => cb(updatedStock));
                }
            });

        }, 1000); // 1-second ticks
    }
}


