                            <span className={`absolute top-2 right-2 w-2 h-2 bg-red-500 rounded-full border ${isLight ? 'border-white' : `border-${theme}-900`}`}></span>
                        </button>
                    </div>
                </header>

                {/* Main Content Area */}
                <div className="flex-1 overflow-y-auto p-4 md:p-6 relative">
                    {renderContent()}
                </div>
            </main>
            {/* ChatBot Overlay */}
            <ChatBot />
        </div>
    );
};

